{
  "domain_analysis": {
    "business_context": "A global logistics platform is implementing a driver earnings transparency feature that must comply with three distinct regulatory regimes. The feature displays real-time earnings breakdowns (base pay, per-delivery bonus, tips, deductions) to drivers. The core complexity is that driver classification (employee vs. independent contractor) and local labor law fundamentally change what MUST be shown, what CAN be shown, and what governance approvals are required before the feature can go live in each jurisdiction.",
    "bounded_context": "Driver Compensation & Earnings Visibility",
    "ubiquitous_language": [
      { "term": "Base Pay", "definition": "The fixed or hourly compensation a driver receives for availability/work time, independent of delivery volume. For employees (CA), this must meet or exceed minimum wage. For contractors (Indonesia), this is the per-task base rate agreed in the service contract." },
      { "term": "Per-Delivery Bonus", "definition": "Variable compensation awarded per completed delivery, often based on distance, time, or demand multipliers." },
      { "term": "Tip", "definition": "Voluntary gratuity from a customer to a driver. In all jurisdictions, tips belong to the driver and must never be counted toward base pay or minimum wage calculations." },
      { "term": "Deduction", "definition": "Any amount subtracted from gross earnings — e.g., platform fees, equipment rental, insurance contributions, tax withholdings. The legal constraints on what may be deducted and how it must be disclosed vary by jurisdiction and driver classification." },
      { "term": "Earnings Breakdown", "definition": "The itemized, per-period or per-delivery view of all compensation components and deductions, shown to the driver." },
      { "term": "Driver Classification", "definition": "The legal labor status of the driver in their operating jurisdiction: 'employee' or 'independent_contractor'. This is determined by local law and governs which compensation rules apply." },
      { "term": "Works Council Approval (Betriebsrat)", "definition": "In Germany, a co-determination body with legal authority to approve or reject changes to systems that display or affect compensation. Rollout in Germany is legally blocked until this approval is obtained." },
      { "term": "Wage Transparency", "definition": "The legal obligation (where applicable) to provide workers with clear, itemized, and timely visibility into how their pay is calculated." },
      { "term": "Jurisdiction", "definition": "The legal region in which a driver operates, which determines classification, disclosure requirements, and governance constraints." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "Every earnings breakdown MUST display all four components: base pay, per-delivery bonus, tips, and deductions. No component may be hidden or aggregated into another.",
      "invariant": true,
      "invariant_justification": "Combining or hiding components (e.g., rolling tips into base pay, or hiding deductions) corrupts the data integrity of the earnings record and violates the fundamental purpose of the feature.",
      "testable_assertion": "For any earnings breakdown record, exactly four top-level line-item categories exist: base_pay, per_delivery_bonus, tips, deductions."
    },
    {
      "id": "BR-2",
      "rule": "Tips must never be counted as or offset against base pay or minimum wage calculations.",
      "invariant": true,
      "invariant_justification": "This is a legal constraint in California (Labor Code §351) and a universal platform integrity rule. Violating it would constitute wage theft for employees and misrepresentation for contractors.",
      "testable_assertion": "The minimum wage compliance calculation for employee-classified drivers never includes tip amounts as a credit toward the minimum wage floor."
    },
    {
      "id": "BR-3",
      "rule": "In California, drivers are classified as employees under AB5. The earnings breakdown MUST include: itemized deductions with legal justification for each, hourly base pay rate, hours worked, and confirmation that total compensation meets or exceeds applicable minimum wage.",
      "invariant": true,
      "invariant_justification": "California Labor Code §226 requires itemized wage statements for employees. Failure to comply exposes the platform to statutory penalties per pay period per driver.",
      "testable_assertion": "For any driver with jurisdiction='CA', the earnings breakdown includes hourly_rate, hours_worked, itemized deductions each with a deduction_reason, and a minimum_wage_compliance flag that is always computed and displayed."
    },
    {
      "id": "BR-4",
      "rule": "In Germany, the earnings transparency feature MUST NOT be rolled out to drivers until explicit Works Council (Betriebsrat) approval has been obtained and recorded in the system.",
      "invariant": true,
      "invariant_justification": "German Works Constitution Act (BetrVG §87) grants the Betriebsrat co-determination rights over monitoring and compensation display systems. Deploying without approval is a legal violation that can result in injunctions and nullification.",
      "testable_assertion": "The feature flag for earnings_transparency in jurisdiction='DE' cannot be set to enabled unless a works_council_approval record exists with status='approved' and a valid approval_date."
    },
    {
      "id": "BR-5",
      "rule": "Deductions must be individually itemized with a category and description. Lump-sum or unexplained deductions are prohibited.",
      "invariant": true,
      "invariant_justification": "An opaque deduction defeats the purpose of transparency and violates California's itemization requirements. It also destroys auditability.",
      "testable_assertion": "Every deduction line item has a non-empty category and a non-empty description. No single deduction labeled 'other' or 'miscellaneous' exceeds a platform-defined threshold without further breakdown."
    },
    {
      "id": "BR-6",
      "rule": "In Indonesia, drivers are independent contractors. The earnings breakdown displays gross earnings and platform fees. The platform is NOT required to show tax withholdings or minimum wage compliance, but MUST show all platform-imposed deductions (service fees, commissions).",
      "invariant": false,
      "invariant_justification": "This is a policy decision reflecting current Indonesian regulation. If Indonesia introduces contractor transparency laws, this rule would change. The platform may also voluntarily increase transparency beyond the legal minimum.",
      "testable_assertion": "For any driver with jurisdiction='ID', the earnings breakdown includes gross_earnings and all platform_fee line items. Tax withholding fields may be absent without triggering a compliance violation."
    },
    {
      "id": "BR-7",
      "rule": "Earnings data must be available in near-real-time: within 5 minutes of a delivery completion event, the earnings breakdown for that delivery must be visible to the driver.",
      "invariant": false,
      "invariant_justification": "The 'real-time' requirement from the spec is a business SLA, not a physical constraint. The threshold (5 minutes) is a policy choice that could be adjusted.",
      "testable_assertion": "The p95 latency between a delivery_completed event and the corresponding earnings_breakdown being queryable by the driver is <= 300 seconds."
    },
    {
      "id": "BR-8",
      "rule": "The earnings breakdown for employee-classified drivers (CA, DE) must be retained for the legally mandated period (CA: 3 years under Labor Code §226; DE: per applicable retention laws). Contractor earnings records (ID) follow platform retention policy.",
      "invariant": true,
      "invariant_justification": "Premature deletion of employee wage records violates statutory retention requirements and eliminates the platform's ability to defend against wage claims.",
      "testable_assertion": "No earnings_breakdown record for jurisdiction='CA' is deleted or archived-without-retrieval before 3 years from its creation date."
    },
    {
      "id": "BR-9",
      "rule": "Currency and locale formatting must match the driver's operating jurisdiction. CA: USD, DE: EUR, ID: IDR.",
      "invariant": true,
      "invariant_justification": "Displaying earnings in the wrong currency corrupts the data — a driver seeing '50' in USD vs IDR is off by ~15,000x. This is data integrity, not formatting preference.",
      "testable_assertion": "Every monetary value in an earnings breakdown is denominated in the currency matching the driver's jurisdiction, and formatted per that locale's conventions."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A driver in California completes a delivery",
      "when": "They view their earnings breakdown",
      "then": "They see base pay (with hourly rate and hours worked), per-delivery bonus, tips (separate from base pay), and individually itemized deductions with reasons, plus a minimum wage compliance indicator — all in USD"
    },
    {
      "id": "AC-2",
      "given": "The Works Council in Germany has NOT yet approved the earnings transparency feature",
      "when": "A German driver attempts to access the earnings breakdown",
      "then": "The feature is unavailable; the driver sees a message explaining the feature is pending approval, NOT a degraded or partial view"
    },
    {
      "id": "AC-3",
      "given": "The Works Council in Germany HAS approved the feature",
      "when": "A German driver completes a delivery and views their earnings breakdown",
      "then": "They see the full earnings breakdown with all four components, itemized deductions, in EUR, compliant with whatever specific display requirements the Works Council stipulated in their approval"
    },
    {
      "id": "AC-4",
      "given": "A driver in Indonesia completes a delivery",
      "when": "They view their earnings breakdown",
      "then": "They see gross earnings, per-delivery bonus, tips, and all platform-imposed fees/commissions itemized — all in IDR"
    },
    {
      "id": "AC-5",
      "given": "A driver completes a delivery in any jurisdiction",
      "when": "5 minutes have elapsed since the delivery_completed event",
      "then": "The earnings breakdown for that delivery is visible and fully populated in the driver's earnings view"
    },
    {
      "id": "AC-6",
      "given": "A California driver's earnings for a period result in an effective hourly rate below the applicable minimum wage",
      "when": "The earnings breakdown is generated",
      "then": "The system flags the shortfall, the minimum_wage_compliance indicator shows non-compliant, and the platform's payroll/compliance team is alerted automatically"
    },
    {
      "id": "AC-7",
      "given": "A deduction is applied to any driver's earnings",
      "when": "The earnings breakdown is displayed",
      "then": "The deduction appears as its own line item with a category and human-readable description — never as part of an undifferentiated lump sum"
    },
    {
      "id": "AC-8",
      "given": "An administrator attempts to enable the earnings transparency feature for Germany",
      "when": "No works_council_approval record with status 'approved' exists in the system",
      "then": "The system rejects the enablement and returns an error citing missing Works Council approval"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A driver operates across jurisdiction boundaries (e.g., starts in one jurisdiction, delivers in another)",
      "expected_behavior": "Earnings are attributed to the jurisdiction where the delivery was completed. The classification and rules of that jurisdiction apply to that delivery's earnings breakdown."
    },
    {
      "scenario": "A California driver's only compensation for a period is tips (base pay error or system failure)",
      "expected_behavior": "The system must still display base_pay as a line item (showing $0.00), flag minimum wage non-compliance, and trigger an alert. The breakdown must never hide the zero."
    },
    {
      "scenario": "A deduction exceeds the driver's gross earnings for a delivery, resulting in negative net pay",
      "expected_behavior": "The earnings breakdown must show the negative net amount transparently. For employee-classified drivers, this likely indicates an illegal deduction and must trigger a compliance alert."
    },
    {
      "scenario": "The Works Council in Germany provides conditional approval (e.g., 'approved but deductions must not show individual delivery penalties')",
      "expected_behavior": "The system must be configurable to enforce Works Council conditions per jurisdiction. The approval record should capture conditions, and the display logic must respect them. This is not a generic feature flag — it requires conditional display rules."
    },
    {
      "scenario": "A tip is later adjusted (customer disputes, fraud reversal) after the driver has already seen the earnings breakdown",
      "expected_behavior": "The adjustment must appear as a new, clearly-labeled line item in a subsequent period — never silently modify the already-displayed breakdown. An audit trail of the original and adjusted amounts must be retained."
    },
    {
      "scenario": "Real-time earnings data is delayed beyond the 5-minute SLA (system outage, queue backlog)",
      "expected_behavior": "The driver sees a clear indication that earnings data is pending/delayed rather than showing stale or incomplete data as if it were final. No partial breakdown should appear without a 'provisional' or 'pending' label."
    },
    {
      "scenario": "A driver in Indonesia is reclassified as an employee due to regulatory change",
      "expected_behavior": "The system must support jurisdiction-level classification changes. Upon reclassification, all forward-looking earnings breakdowns must comply with employee-level transparency rules. Historical records retain their original classification but are flagged for review."
    },
    {
      "scenario": "Platform applies a deduction category that has no localized description in the driver's language",
      "expected_behavior": "The deduction must still appear itemized — falling back to the default language (English) rather than being hidden. A missing translation is a UX issue; a hidden deduction is a compliance violation."
    }
  ],

  "business_impact": {
    "financial": "Non-compliance with California AB5 and wage statement laws (Labor Code §226) carries penalties of $50-$100 per employee per pay period, scaling rapidly across a driver fleet. Germany: unauthorized rollout could result in Works Council injunctions halting the feature entirely. Conversely, voluntary transparency in Indonesia may improve driver retention, reducing recruitment costs (typically $200-500 per driver in logistics).",
    "operational": "The feature requires jurisdiction-aware configuration, not a single global rollout. This introduces operational complexity: per-jurisdiction feature flags, a Works Council approval workflow, locale-specific formatting, and classification-aware display logic. The real-time SLA (5 minutes) requires event-driven architecture rather than batch processing.",
    "user": "Drivers gain trust and clarity into their compensation, directly impacting satisfaction and retention. In California, this fulfills a legal expectation. In Indonesia, it differentiates the platform competitively. However, poorly implemented transparency (e.g., confusing deductions, wrong currency) could erode trust worse than no transparency at all.",
    "risk": "HIGH in California (statutory penalties, class-action exposure for wage statement violations). HIGH in Germany (Works Council injunction risk if deployed prematurely). LOW in Indonesia (no legal mandate, but reputational risk if transparency is perceived as misleading). Cross-cutting risk: if the tip-separation invariant (BR-2) is violated, this constitutes wage theft in employee jurisdictions.",
    "stakeholders_affected": [
      { "group": "Drivers (CA)", "impact": "Legally entitled to itemized wage statements. This feature fulfills that right. Incorrect implementation exposes them to underpayment without visibility." },
      { "group": "Drivers (DE)", "impact": "Cannot access the feature until Works Council approves. Must be clearly communicated to avoid frustration or perception of discrimination vs. other regions." },
      { "group": "Drivers (ID)", "impact": "Gain voluntary transparency that improves trust. No legal entitlement, so the platform has more flexibility in presentation." },
      { "group": "Works Council (DE)", "impact": "Must be engaged as a co-decision-maker, not merely notified. Their conditions may shape the DE-specific implementation significantly." },
      { "group": "Platform Legal/Compliance Team", "impact": "Must validate jurisdiction-specific rules, approve deduction categories, and monitor minimum wage compliance alerts." },
      { "group": "Platform Finance/Payroll", "impact": "Must ensure earnings data feeding the transparency feature is consistent with actual payroll disbursements. Any discrepancy between displayed and paid amounts is a severe compliance and trust issue." },
      { "group": "Customers", "impact": "Indirect. Tip transparency may influence tipping behavior. Customers should understand their tips go fully to drivers (reinforced by BR-2)." }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec is a single sentence ('Show each driver their earnings breakdown in real time') with jurisdiction context provided. Multiple critical details are unspecified: what constitutes 'real time' exactly, whether German Works Council has been contacted, what specific deduction categories exist, how minimum wage compliance should be calculated (per-delivery vs. per-period), and whether the platform already has driver classification data. The legal/regulatory requirements are well-known publicly but have NOT been reviewed by legal counsel for this specific implementation. The Germany Works Council dimension introduces a hard unknown — their conditions could materially reshape the DE implementation.",
    "high_confidence_areas": [
      "Tips must never offset base pay or minimum wage (universal labor law principle)",
      "California requires itemized wage statements for employees (Labor Code §226 is unambiguous)",
      "Germany requires Works Council approval before deployment (BetrVG §87 is unambiguous)",
      "Deductions must be individually itemized for transparency to be meaningful",
      "Currency must match jurisdiction"
    ],
    "low_confidence_areas": [
      "Exact minimum wage compliance calculation method (per-delivery vs. per-shift vs. per-pay-period) — California law has nuances around piece-rate workers",
      "German Works Council conditions — unknown until engagement occurs, could significantly alter DE requirements",
      "Indonesia-specific regulations — assumed no transparency mandate, but local counsel has not confirmed",
      "Data retention periods for Germany — varies by state and applicable law",
      "Whether 'real time' means per-delivery or continuously updating aggregated view"
    ],
    "assumptions": [
      "Driver classification data (employee vs. contractor) already exists and is accurate in the system per jurisdiction",
      "The platform has an existing feature flag system that can be conditioned on jurisdiction and external approval records",
      "Earnings data (base pay, bonuses, tips, deductions) is already captured at the delivery event level, even if not yet surfaced to drivers",
      "The Works Council in Germany has not yet been engaged on this specific feature",
      "Indonesian regulatory environment has not changed to require contractor pay transparency"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec says 'real time' but does not define latency tolerance. For employee jurisdictions, there is a difference between showing earnings immediately after each delivery vs. showing a continuously-updating shift/period total. California piece-rate law may require per-piece visibility. The 5-minute SLA in BR-7 is my best interpretation but needs product/legal confirmation.",
      "affected_stakeholders": ["Drivers (all jurisdictions)", "Platform Engineering", "Legal/Compliance"],
      "options": ["Per-delivery breakdown available within seconds (event-driven)", "Per-delivery within 5 minutes (near-real-time with SLA)", "Shift-end summary only (batch, likely non-compliant for CA)"],
      "recommendation": "Per-delivery within 5 minutes as the minimum SLA, with best-effort sub-minute delivery. Shift-end-only is almost certainly non-compliant with 'real time' intent and CA requirements."
    },
    {
      "type": "ambiguity",
      "description": "Minimum wage compliance calculation period is undefined. California AB5 drivers may be subject to hourly minimum wage, but the platform may use piece-rate compensation. Labor Code §226.2 has specific piece-rate requirements. The earnings breakdown must handle this correctly — calculating compliance per-delivery is meaningless; it must be per-pay-period or per-shift.",
      "affected_stakeholders": ["Drivers (CA)", "Legal/Compliance", "Platform Payroll"],
      "options": ["Per-pay-period minimum wage compliance check", "Per-shift compliance check", "Per-delivery (incorrect but simpler)"],
      "recommendation": "Per-pay-period, aligned with actual payroll cycle, with per-shift visibility as a leading indicator. Legal counsel must confirm."
    },
    {
      "type": "missing_context",
      "description": "The German Works Council's stance and any pre-existing agreements on compensation display systems are unknown. Their conditions could add requirements (e.g., anonymized aggregate comparisons, specific deduction categorizations) or prohibit certain displays (e.g., individual performance metrics tied to pay). This is not a formality — it is a legal gate.",
      "affected_stakeholders": ["Drivers (DE)", "Works Council (DE)", "Platform Legal (DE)", "Product Team"],
      "options": ["Build DE feature speculatively and adapt after approval", "Engage Works Council first, build DE feature to their requirements", "Launch in CA and ID first while DE engagement proceeds in parallel"],
      "recommendation": "Launch CA and ID first. Engage Works Council immediately in parallel. Do NOT build DE-specific logic until their conditions are known — speculative work may be wasted or counterproductive to negotiations."
    },
    {
      "type": "missing_context",
      "description": "No legal review has been conducted for this specific feature implementation. The business rules above are based on general knowledge of CA, DE, and ID labor law, but have not been validated by qualified legal counsel in each jurisdiction. This is especially critical for California piece-rate wage statement requirements and Indonesian contractor law.",
      "affected_stakeholders": ["All drivers", "Platform Legal", "Platform Executive Leadership"],
      "options": ["Proceed with engineering based on general legal knowledge", "Gate feature development on legal review completion", "Proceed with engineering but gate rollout on legal sign-off"],
      "recommendation": "Proceed with engineering using these rules as a foundation, but GATE ROLLOUT in each jurisdiction on explicit legal sign-off. Legal review must happen in parallel with development, not after."
    }
  ],

  "rejection_reasons": []
}

